import{_ as t,o as e,c as s,a2 as n}from"./chunks/framework.LN3EJxkW.js";const b=JSON.parse('{"title":"建立交互状态清单","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/deconstruction/03-state-inventory.md","filePath":"03-interaction-design/notes/deconstruction/03-state-inventory.md","lastUpdated":1784248569000}'),i={name:"03-interaction-design/notes/deconstruction/03-state-inventory.md"};function l(d,a,r,p,o,h){return e(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="建立交互状态清单" tabindex="-1">建立交互状态清单 <a class="header-anchor" href="#建立交互状态清单" aria-label="Permalink to &quot;建立交互状态清单&quot;">​</a></h1><p>状态清单系统记录系统、对象、页面区域和控件在不同条件下可能呈现的状态，以及每个状态的进入条件、可用操作、反馈、持久化与恢复。它用于发现静态截图和主路径中没有呈现的行为缺口。</p><h2 id="状态与页面的区别" tabindex="-1">状态与页面的区别 <a class="header-anchor" href="#状态与页面的区别" aria-label="Permalink to &quot;状态与页面的区别&quot;">​</a></h2><p>状态是某一时刻的条件集合，不一定对应独立页面。一个页面可能同时处于：系统在线、项目已归档、列表加载成功、某个文件处理中、保存按钮禁用。把整页只标为“成功”会掩盖局部失败与对象差异。</p><table tabindex="0"><thead><tr><th>层次</th><th>状态对象</th><th>示例</th></tr></thead><tbody><tr><td>系统</td><td>整个服务或依赖</td><td>在线、维护、认证不可用</td></tr><tr><td>会话与权限</td><td>当前身份和授权</td><td>未登录、会话过期、只读、可编辑</td></tr><tr><td>业务对象</td><td>数据实体生命周期</td><td>草稿、审批中、已发布、已归档</td></tr><tr><td>页面或区域</td><td>数据获取和呈现</td><td>初始、加载、空、失败、过期</td></tr><tr><td>控件</td><td>单个交互元素</td><td>默认、焦点、按下、禁用、忙碌、无效</td></tr></tbody></table><h2 id="一个完整状态定义" tabindex="-1">一个完整状态定义 <a class="header-anchor" href="#一个完整状态定义" aria-label="Permalink to &quot;一个完整状态定义&quot;">​</a></h2><p>状态名称不能代替行为。每项至少记录：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>状态名</span></span>
<span class="line"><span>进入条件</span></span>
<span class="line"><span>可见内容与反馈</span></span>
<span class="line"><span>允许和禁止的操作</span></span>
<span class="line"><span>数据是否持久化</span></span>
<span class="line"><span>离开条件与目标状态</span></span>
<span class="line"><span>刷新、返回和重新登录后的恢复</span></span>
<span class="line"><span>键盘与辅助技术表达</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">stateDiagram-v2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    [*] --&gt; Initial</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Initial --&gt; Loading: 发起读取</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Loading --&gt; Empty: 成功且集合为零</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Loading --&gt; Ready: 成功且有数据</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Loading --&gt; Error: 请求失败</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Ready --&gt; Stale: 收到版本变化信号</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Stale --&gt; Loading: 刷新</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Error --&gt; Loading: 重试</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Empty --&gt; Loading: 创建后刷新</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>状态转换的标签应是可判定事件或条件，不写“用户感觉不对”。</p><h2 id="基础页面状态" tabindex="-1">基础页面状态 <a class="header-anchor" href="#基础页面状态" aria-label="Permalink to &quot;基础页面状态&quot;">​</a></h2><h3 id="初始" tabindex="-1">初始 <a class="header-anchor" href="#初始" aria-label="Permalink to &quot;初始&quot;">​</a></h3><p>组件已创建但尚未开始读取，或等待必要输入。初始状态不能闪现错误默认值。若页面立即读取数据，初始状态可以极短，但实现仍要避免未初始化数据被当作空结果。</p><h3 id="加载" tabindex="-1">加载 <a class="header-anchor" href="#加载" aria-label="Permalink to &quot;加载&quot;">​</a></h3><p>已发起操作，结果未确定。定义：加载对象、是否保留旧数据、能否取消、超时行为、辅助技术如何获知。首次加载、后台刷新和提交中不应统一为整页遮罩。</p><h3 id="空" tabindex="-1">空 <a class="header-anchor" href="#空" aria-label="Permalink to &quot;空&quot;">​</a></h3><p>权威读取成功且集合确实为空。区分：</p><ul><li>从未创建数据；</li><li>当前筛选无结果；</li><li>数据因权限不可见；</li><li>数据被归档或删除；</li><li>读取失败但界面错误地显示为空。</li></ul><p>每种状态的解释和下一步不同。</p><h3 id="就绪或成功" tabindex="-1">就绪或成功 <a class="header-anchor" href="#就绪或成功" aria-label="Permalink to &quot;就绪或成功&quot;">​</a></h3><p>数据可用并能继续任务。需要记录数据版本、部分模块是否失败、操作权限和是否显示过期缓存。成功不是无条件终态，用户可继续编辑、刷新或进入其他对象状态。</p><h3 id="失败" tabindex="-1">失败 <a class="header-anchor" href="#失败" aria-label="Permalink to &quot;失败&quot;">​</a></h3><p>说明失败阶段、影响范围、是否有副作用、输入保留与可执行下一步。按可恢复性区分暂时失败、需修正输入、权限失败、永久规则失败和未知结果。</p><h2 id="必须主动检查的状态" tabindex="-1">必须主动检查的状态 <a class="header-anchor" href="#必须主动检查的状态" aria-label="Permalink to &quot;必须主动检查的状态&quot;">​</a></h2><h3 id="部分成功" tabindex="-1">部分成功 <a class="header-anchor" href="#部分成功" aria-label="Permalink to &quot;部分成功&quot;">​</a></h3><p>批量或多依赖任务中只有一部分完成。逐项列出权威结果和重试范围；不要用一个错误覆盖成功项，也不要重新执行已成功副作用。</p><h3 id="无权限" tabindex="-1">无权限 <a class="header-anchor" href="#无权限" aria-label="Permalink to &quot;无权限&quot;">​</a></h3><p>区分未认证、已认证但无权限、对象不存在与权限刚被撤销。安全要求可能不允许暴露对象是否存在，但仍要提供不泄密的下一步。</p><h3 id="离线" tabindex="-1">离线 <a class="header-anchor" href="#离线" aria-label="Permalink to &quot;离线&quot;">​</a></h3><p>说明是只读缓存、允许排队写入还是完全不可用；排队不等于同步成功。恢复网络后需显示同步、冲突和最终结果。</p><h3 id="过期数据" tabindex="-1">过期数据 <a class="header-anchor" href="#过期数据" aria-label="Permalink to &quot;过期数据&quot;">​</a></h3><p>界面显示的数据版本落后于权威状态。可以自动刷新、提示刷新或允许比较；高风险提交前必须重新校验权限和对象版本。</p><h3 id="取消" tabindex="-1">取消 <a class="header-anchor" href="#取消" aria-label="Permalink to &quot;取消&quot;">​</a></h3><p>取消是否终止客户端操作、服务端任务或仅停止等待必须明确。取消后清理临时数据，保留可恢复输入并给出确认。</p><h3 id="重试" tabindex="-1">重试 <a class="header-anchor" href="#重试" aria-label="Permalink to &quot;重试&quot;">​</a></h3><p>重试再次执行同一意图。写操作需要幂等语义；重试次数、退避、可见状态和永久失败条件应定义。</p><h3 id="并发冲突" tabindex="-1">并发冲突 <a class="header-anchor" href="#并发冲突" aria-label="Permalink to &quot;并发冲突&quot;">​</a></h3><p>其他用户、标签页或设备修改了同一对象。系统可以合并不冲突字段、要求选择版本或拒绝覆盖。不能静默丢弃任一方有效数据。</p><h2 id="控件状态清单" tabindex="-1">控件状态清单 <a class="header-anchor" href="#控件状态清单" aria-label="Permalink to &quot;控件状态清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>进入条件</th><th>必须表达</th></tr></thead><tbody><tr><td>默认</td><td>可操作且未聚焦</td><td>名称、作用与可供性</td></tr><tr><td>悬停</td><td>指针位于目标上</td><td>不能成为唯一信息渠道</td></tr><tr><td>焦点</td><td>键盘或程序焦点进入</td><td>可见焦点；名称、角色和值</td></tr><tr><td>按下</td><td>激活过程中</td><td>即时反馈，不等于最终成功</td></tr><tr><td>选中</td><td>当前值被选择</td><td>程序化状态，不只颜色</td></tr><tr><td>禁用</td><td>当前不能操作</td><td>原因与恢复条件可获得</td></tr><tr><td>只读</td><td>可查看但不可修改</td><td>与禁用和普通文本区分</td></tr><tr><td>忙碌</td><td>正在处理</td><td>防重复策略、进度或等待信息</td></tr><tr><td>无效</td><td>值未通过规则</td><td>文本错误、关联字段和修正方式</td></tr></tbody></table><p>焦点与悬停可以和选中、无效等状态组合。设计规范应定义组合优先级，例如无效字段获得焦点时，焦点指示不能被红色错误边框覆盖到不可见。</p><h2 id="建立状态矩阵" tabindex="-1">建立状态矩阵 <a class="header-anchor" href="#建立状态矩阵" aria-label="Permalink to &quot;建立状态矩阵&quot;">​</a></h2><p>先列关键维度，再选择有意义组合。不要机械做所有笛卡尔积，但要覆盖会改变行为的条件。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>身份：未登录 | 查看者 | 编辑者 | 管理员</span></span>
<span class="line"><span>对象：草稿 | 审批中 | 已发布 | 已归档</span></span>
<span class="line"><span>网络：在线 | 慢 | 离线 | 恢复中</span></span>
<span class="line"><span>数据：首次加载 | 有数据 | 空 | 过期 | 冲突</span></span>
<span class="line"><span>操作：未开始 | 提交中 | 成功 | 失败 | 取消</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>用不变量排除不可能组合，例如未登录用户不应拥有项目编辑权限；用风险优先级选择需要真实验证的组合。</p><h2 id="完整案例-文件上传与服务端解析" tabindex="-1">完整案例：文件上传与服务端解析 <a class="header-anchor" href="#完整案例-文件上传与服务端解析" aria-label="Permalink to &quot;完整案例：文件上传与服务端解析&quot;">​</a></h2><h3 id="具体输入" tabindex="-1">具体输入 <a class="header-anchor" href="#具体输入" aria-label="Permalink to &quot;具体输入&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>文件：members.csv，2.4 MB，100 行</span></span>
<span class="line"><span>预期：导入 98 个新成员，2 行格式错误</span></span>
<span class="line"><span>角色：项目管理员</span></span>
<span class="line"><span>网络：上传期间短暂断开 3 秒</span></span>
<span class="line"><span>服务端：上传完成后异步解析</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="状态清单" tabindex="-1">状态清单 <a class="header-anchor" href="#状态清单" aria-label="Permalink to &quot;状态清单&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>进入条件</th><th>可见结果</th><th>操作</th><th>下一状态</th></tr></thead><tbody><tr><td><code>selected</code></td><td>本地文件已选</td><td>文件名、大小、删除</td><td>上传、替换、取消</td><td><code>prechecking</code></td></tr><tr><td><code>prechecking</code></td><td>开始本地格式检查</td><td>“正在检查文件”</td><td>取消</td><td><code>invalid-local</code> / <code>uploading</code></td></tr><tr><td><code>uploading</code></td><td>预检通过并开始传输</td><td>传输进度</td><td>取消</td><td><code>paused-offline</code> / <code>processing</code></td></tr><tr><td><code>paused-offline</code></td><td>网络中断</td><td>已上传比例、离线说明</td><td>等待、取消</td><td><code>uploading</code></td></tr><tr><td><code>processing</code></td><td>服务端收到完整文件</td><td>“已上传，正在解析”</td><td>离开、查看任务</td><td><code>partial</code> / <code>complete</code> / <code>failed</code></td></tr><tr><td><code>partial</code></td><td>部分行导入失败</td><td>98 成功、2 失败及报告</td><td>下载错误、修正失败项</td><td><code>processing</code></td></tr><tr><td><code>complete</code></td><td>全部预期写入完成</td><td>实际数量、导入 ID</td><td>查看成员</td><td>终态</td></tr><tr><td><code>failed</code></td><td>永久解析失败</td><td>原因、是否写入任何数据</td><td>替换文件或联系支持</td><td><code>selected</code></td></tr></tbody></table><h3 id="逐步处理" tabindex="-1">逐步处理 <a class="header-anchor" href="#逐步处理" aria-label="Permalink to &quot;逐步处理&quot;">​</a></h3><ol><li>选择文件后，本地只检查大小、扩展名与表头，不能宣称业务数据有效。</li><li>上传到 45% 时网络中断，状态进入 <code>paused-offline</code>，进度不回到 0。</li><li>网络恢复后根据协议续传或重新上传；若重新上传，复用同一导入意图 ID。</li><li>传输完成进入 <code>processing</code>，允许用户离开页面并在导入任务列表恢复。</li><li>服务端逐行校验，98 行提交，2 行记录错误；产品规则允许部分成功。</li><li>结果显示成功和失败数量、错误行号与修正格式，重试只提交失败项。</li></ol><h3 id="可观察输出" tabindex="-1">可观察输出 <a class="header-anchor" href="#可观察输出" aria-label="Permalink to &quot;可观察输出&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>导入任务：IMP-3021</span></span>
<span class="line"><span>状态：部分完成</span></span>
<span class="line"><span>成功：98</span></span>
<span class="line"><span>失败：2（第 17、64 行）</span></span>
<span class="line"><span>已写入成员：98</span></span>
<span class="line"><span>下一步：下载错误报告 / 修正后重试失败项</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><ul><li>解析服务崩溃且结果未知：状态保持“处理中”或“需要确认”，不能显示空列表。</li><li>用户权限在处理期间被撤销：后台任务按提交时授权策略处理，但后续查看遵守当前权限；具体规则由产品定义。</li><li>同一文件重复提交：幂等键阻止重复创建成员或明确创建新导入版本。</li><li>用户取消处理：若服务端已写入 40 行，必须说明取消是停止剩余行还是回滚全部；不能只隐藏进度。</li></ul><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ol><li>用固定测试文件核对 98/2 输出与数据库记录。</li><li>在上传 0%、45%、100% 与处理期间分别断网、刷新和返回。</li><li>使用重复意图 ID 重试，成员数不重复增加。</li><li>仅用键盘选择、取消、查看错误和重试。</li><li>屏幕阅读器能获知进度阶段变化、部分结果和错误数量。</li></ol><h2 id="可执行工作步骤" tabindex="-1">可执行工作步骤 <a class="header-anchor" href="#可执行工作步骤" aria-label="Permalink to &quot;可执行工作步骤&quot;">​</a></h2><ol><li>按系统、会话、对象、区域和控件列状态对象。</li><li>从主路径提取初始、加载、就绪、成功与失败。</li><li>主动加入空、权限、离线、过期、取消、重试和并发。</li><li>为每个状态写进入、可见、操作、持久化、离开与恢复。</li><li>建立状态转换图和维度矩阵，排除不可能组合。</li><li>将状态映射到真实数据字段、请求结果或条件。</li><li>准备可重复触发每个状态的测试数据或故障开关。</li><li>用刷新、返回、键盘、屏幕阅读器和窄屏验证。</li></ol><h2 id="常见错误与修正" tabindex="-1">常见错误与修正 <a class="header-anchor" href="#常见错误与修正" aria-label="Permalink to &quot;常见错误与修正&quot;">​</a></h2><ul><li>将“空”和“加载失败”显示相同：用权威结果与错误分别建模。</li><li>用页面截图代替状态定义：补进入条件、操作和转换。</li><li>所有错误统一为“重试”：区分输入、权限、永久与未知结果。</li><li>上传到 100% 显示完成：单独建模服务端处理。</li><li>取消只关闭 UI：定义服务端副作用和清理。</li><li>禁用状态只给灰色外观：提供原因与可感知语义。</li><li>状态名无法映射数据：重写为可判定条件。</li><li>只测状态本身，不测刷新与跨设备恢复。</li></ul><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>为“离线编辑笔记并重新同步”建立完整状态清单。</p><p>完成时应满足：</p><ul><li>分开网络、笔记对象、编辑器、同步任务和控件状态；</li><li>每个状态有进入、操作、持久化、离开与恢复；</li><li>覆盖首次离线、已有缓存、排队、同步中、成功、失败和冲突；</li><li>明确“本地已保存”与“云端已同步”的差异；</li><li>可重复制造双端修改和网络恢复；</li><li>键盘与辅助技术能获知保存与同步状态；</li><li>刷新、重启和重新登录后权威结果一致。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/status-messages.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 4.1.3 Status Messages</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/input-assistance.html" target="_blank" rel="noreferrer">W3C WAI：Understanding Guideline 3.3 Input Assistance</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/ARIA/apg/about/introduction/" target="_blank" rel="noreferrer">W3C WAI-ARIA APG：Introduction</a>（访问日期：2026-07-17）</li><li><a href="https://html.spec.whatwg.org/multipage/form-control-infrastructure.html" target="_blank" rel="noreferrer">WHATWG HTML Standard：Form control infrastructure</a>（访问日期：2026-07-17）</li></ul>`,68)])])}const u=t(i,[["render",l]]);export{b as __pageData,u as default};
